const escapeHtml = (value) => value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
export const buildManualHtml = (runId, generatedAt, steps) => {
    const body = steps
        .map((item) => `
        <div class="step">
            <h2 class="step-title">步骤 ${item.step}</h2>
            ${item.action ? `<p class="step-action">动作：${escapeHtml(item.action)}</p>` : ""}
            <p class="step-desc">${escapeHtml(item.desc)}</p>
            ${item.status
        ? `<p class="step-audit">状态：${escapeHtml(item.status)}${item.errorCode ? ` ｜ 错误：${escapeHtml(item.errorCode)}` : ""}${typeof item.retryCount === "number" ? ` ｜ 重试：${item.retryCount}` : ""}${typeof item.latencyMs === "number" ? ` ｜ 耗时：${item.latencyMs}ms` : ""}</p>`
        : ""}
            ${item.pageUrlBefore || item.pageUrlAfter
        ? `<p class="step-url">${item.pageUrlBefore ? `前URL：${escapeHtml(item.pageUrlBefore)}` : ""}${item.pageUrlBefore && item.pageUrlAfter ? " ｜ " : ""}${item.pageUrlAfter ? `后URL：${escapeHtml(item.pageUrlAfter)}` : ""}</p>`
        : ""}
            ${item.image
        ? `<div class="screenshot">
                <img class="step-image" src="${escapeHtml(item.image)}" alt="步骤 ${item.step} 截图">
            </div>`
        : ""}
        </div>`)
        .join("");
    return `<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Web 操作手册 (Run: ${escapeHtml(runId)})</title>
    <style>
        body { font-family: "Microsoft YaHei", "Segoe UI", sans-serif; margin: 0; padding: 20px; background-color: #f5f7fa; color: #303133; }
        .container { max-width: 1000px; margin: 0 auto; background-color: #ffffff; padding: 36px; border-radius: 10px; box-shadow: 0 4px 10px rgba(0, 0, 0, 0.08); }
        h1 { text-align: center; color: #409eff; border-bottom: 2px solid #ebeef5; padding-bottom: 16px; margin: 0 0 16px; }
        .meta { text-align: center; color: #909399; margin-bottom: 26px; font-size: 14px; }
        .meta .run-id { display: inline-block; margin-left: 8px; padding: 2px 8px; border-radius: 999px; background: #ecf5ff; color: #409eff; }
        .step { margin-bottom: 24px; padding: 20px; border: 1px solid #ebeef5; border-radius: 6px; background-color: #fafafa; }
        .step-title { margin: 0 0 10px; color: #303133; font-size: 20px; }
        .step-action { margin: 0 0 10px; color: #909399; font-size: 13px; letter-spacing: 0.3px; }
        .step-desc { margin: 0; color: #606266; font-size: 16px; line-height: 1.7; }
        .step-audit { margin: 10px 0 0; color: #606266; font-size: 13px; line-height: 1.6; }
        .step-url { margin: 6px 0 0; color: #909399; font-size: 12px; line-height: 1.5; word-break: break-all; }
        .screenshot { margin-top: 18px; text-align: center; }
        .step-image { max-width: 100%; border: 1px solid #dcdfe6; border-radius: 6px; box-shadow: 0 2px 6px rgba(0, 0, 0, 0.1); }
        .footer { text-align: center; color: #909399; margin-top: 32px; font-size: 14px; }
    </style>
</head>
<body>
    <div class="container">
        <h1>📘 Web 自动化操作手册</h1>
        <p class="meta">生成时间：${escapeHtml(generatedAt)}<span class="run-id">Run: ${escapeHtml(runId)}</span></p>
${body}
        <div class="footer">
            <p>Generated by TRAE Web Manual Agent</p>
        </div>
    </div>
</body>
</html>`;
};
